191	func buildReframerPrompt(store ExecuteBeadLoopStore, b *bead.Bead) (string, error) {
192		type failureEntry struct {
193			Summary string `json:"summary"`
194			Body    string `json:"body,omitempty"`
195		}
196		type envelope struct {
197			Title          string         `json:"title"`
198			Description    string         `json:"description"`
199			Acceptance     string         `json:"acceptance"`
200			FailureHistory []failureEntry `json:"failure_history"`
201		}
202	
203		env := envelope{
204			Title:       strings.TrimSpace(b.Title),
205			Description: strings.TrimSpace(b.Description),
206			Acceptance:  strings.TrimSpace(b.Acceptance),
207		}
208	
209		if events, err := store.Events(b.ID); err == nil {
210			for i := len(events) - 1; i >= 0 && len(env.FailureHistory) < 5; i-- {
211				ev := events[i]
212				switch ev.Kind {
213				case "bead.result", "execute-bead", "per-bead-budget-exhausted":
214				default:
215					continue
216				}
217				env.FailureHistory = append(env.FailureHistory, failureEntry{
218					Summary: strings.TrimSpace(ev.Summary),
219					Body:    strings.TrimSpace(ev.Body),
220				})
221			}
222		}
223	
224		body, err := json.MarshalIndent(env, "", "  ")
225		if err != nil {
226			return "", fmt.Errorf("reframer: encode prompt: %w", err)
227		}
228	
229		var sb strings.Builder
230		sb.WriteString("MODE: reframe\n")
231		sb.WriteString("You are rewriting a bead's description and acceptance criteria after repeated execution failures.\n")
232		sb.WriteString("Your goal is to produce a clearer, more specific, implementation-ready bead.\n")
233		sb.WriteString("Preservation rules: governing artifact references (FEAT-NNN, ADR-NNN), named test functions (TestFoo), file:line evidence, dependency IDs (ddx-XXXXXXXX), and NON-SCOPE bullets must appear in any rewrite.\n")
234		sb.WriteString("Return exactly one JSON object: {\"description\": string|null, \"acceptance\": string|null}\n")
235		sb.WriteString("Use null to leave a field unchanged. At least one field must be non-null and meaningfully changed.\n")
236		sb.WriteString("Do not include prose or markdown; return only the JSON object.\n\n")
237		sb.WriteString("```json\n")
238		sb.Write(body)
239		sb.WriteString("\n```\n")
240		return sb.String(), nil
241	}
